let buildPaths = []

function pushToPath(path, type) {
    buildPaths.push(`${type}/${path === 'true' ? '*' : path}`)
}

const types = [
    {
        key: 'npm_config_theme',
        name: 'themes',
    },
    {
        key: 'npm_config_plugin',
        name: 'plugins',
    },
    {
        key: 'npm_config_package',
        name: 'packages',
    },
    {
        key: 'npm_config_core',
        name: 'core',
    },
]

