// Frontend Calendar Styles

.calendar-wrapper {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 20px;
    background: #fff;

    .calendar-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        margin-bottom: 15px;

        h5 {
            margin: 0;
            font-size: 18px;
            font-weight: 600;
        }

        .calendar-legend {
            display: flex;
            gap: 15px;
            font-size: 12px;

            .legend-item {
                display: flex;
                align-items: center;
                gap: 6px;

                .dot {
                    width: 10px;
                    height: 10px;
                    border-radius: 50%;
                }

                &.available .dot { background-color: #28a745; }
                &.unavailable .dot { background-color: #dc3545; }
                &.selected .dot { background-color: #007bff; }
            }
        }
    }

    .flatpickr-calendar.frontend-calendar {
        width: 100%;
        box-shadow: none;

        .flatpickr-day {
            &.unavailable {
                background-color: #f8d7da;
                color: #721c24;
                text-decoration: line-through;
                pointer-events: none;
            }

            &.selected {
                background-color: #007bff;
                color: #fff;
                border-color: #007bff;
            }
        }
    }

    .booking-summary {
        margin-top: 20px;
        border-top: 1px solid #e0e0e0;
        padding-top: 20px;

        .summary-content {
            .date-range {
                display: flex;
                justify-content: space-between;
                margin-bottom: 15px;

                .date-item {
                    text-align: center;
                    label {
                        display: block;
                        font-size: 12px;
                        color: #6c757d;
                    }
                    span {
                        font-weight: 600;
                    }
                }
            }

            .pricing-breakdown {
                margin-bottom: 15px;
                .price-item {
                    display: flex;
                    justify-content: space-between;
                    padding: 8px 0;
                    border-bottom: 1px dashed #e0e0e0;

                    &:last-child {
                        border-bottom: none;
                    }
                }
            }

            .total-price {
                text-align: right;
                font-size: 18px;
                font-weight: 700;
                margin-bottom: 20px;
            }
        }
    }
}

