'use strict'

const laravelValidation = {
    implicitRules: ['Required', 'Confirmed'],

    /**
     * Initialize laravel validations.
     */
    init: function () {
        // Disable class rules and attribute rules
        $.validator.classRuleSettings = {}
        $.validator.attributeRules = function () {
            this.rules = {}
        }

        // Assign arrayRules method to dataRules
        $.validator.dataRules = this.arrayRules

        // Extend the validator prototype to include arrayRulesCache
        if (!$.validator.prototype.arrayRulesCache) {
            $.validator.prototype.arrayRulesCache = {}
        }

        // Register validations methods
        this.setupValidations()
    },

    arrayRules: function (element) {
        const rules = {}
        const validator = $.data(element.form, 'validator')

        // Check if validator exists
        if (!validator) {
            return rules
        }

        // Initialize cache if it doesn't exist
        if (!validator.arrayRulesCache) {
            validator.arrayRulesCache = {}
        }

        const cache = validator.arrayRulesCache

        // Is not an Array
        if (element.name && element.name.indexOf('[') === -1) {
            return rules
        }

        if (!(element.name in cache)) {
            cache[element.name] = {}
        }

        // Check if settings.rules exists
        if (validator.settings && validator.settings.rules) {
            $.each(validator.settings.rules, function (name, tmpRules) {
                if (name in cache[element.name]) {
                    $.extend(rules, cache[element.name][name])
                } else {
                    cache[element.name][name] = {}
                    const nameRegExp = laravelValidation.helpers.regexFromWildcard(name)
                    if (element.name && typeof element.name === 'string' && element.name.match(nameRegExp)) {
                        const newRules = $.validator.normalizeRule(tmpRules) || {}
                        cache[element.name][name] = newRules
                        $.extend(rules, newRules)
                    }
                }
            })
        }

        return rules
    },

    setupValidations: function () {
        /**
         * Create JQueryValidation check to validate Laravel rules.
         */

        $.validator.addMethod(
            'laravelValidation',
            function (value, element, params) {
                const validator = this
                let validated = true
                const previous = this.previousValue(element)

                // put Implicit rules in front
                const rules = []
                $.each(params, function (i, param) {
                    if (param[3] || laravelValidation.implicitRules.indexOf(param[0]) !== -1) {
                        rules.unshift(param)
                    } else {
                        rules.push(param)
                    }
                })

                $.each(rules, function (i, param) {
                    const implicit = param[3] || laravelValidation.implicitRules.indexOf(param[0]) !== -1
                    const rule = param[0]
                    const message = param[2]

                    if (!implicit && validator.optional(element)) {
                        validated = 'dependency-mismatch'
                        return false
                    }

                    if (laravelValidation.methods[rule] !== undefined) {
                        validated = laravelValidation.methods[rule].call(
                            validator,
                            value,
                            element,
                            param[1],
                            function (valid) {
                                validator.settings.messages[element.name].laravelValidationRemote =
                                    previous.originalMessage
                                if (valid) {
                                    const submitted = validator.formSubmitted
                                    validator.prepareElement(element)
                                    validator.formSubmitted = submitted
                                    validator.successList.push(element)
                                    delete validator.invalid[element.name]
                                    validator.showErrors()
                                } else {
                                    const errors = {}
                                    errors[element.name] = previous.message = $.isFunction(message)
                                        ? message(value)
                                        : message
                                    validator.invalid[element.name] = true
                                    validator.showErrors(errors)
                                }
                                validator.showErrors(validator.errorMap)
                                previous.valid = valid
                            }
                        )
                    } else {
                        validated = false
                    }

                    if (validated !== true) {
                        if (!validator.settings.messages[element.name]) {
                            validator.settings.messages[element.name] = {}
                        }
                        validator.settings.messages[element.name].laravelValidation = message
                        return false
                    }
                })

                return validated
            },
            ''
        )

        /**
         * Create JQueryValidation check to validate Remote Laravel rules.
         */
        $.validator.addMethod(
            'laravelValidationRemote',
            function (value, element, params) {
                const validator = this
                const previous = this.previousValue(element)

                let implicit = false,
                    check = params[0][1],
                    attribute = element.name,
                    token = check[1],
                    validateAll = check[2]

                $.each(params, function (i, parameters) {
                    implicit = implicit || parameters[3]
                })

                if (!implicit && validator.optional(element)) {
                    return 'dependency-mismatch'
                }

                let data

                if (!validator.settings.messages[element.name]) {
                    validator.settings.messages[element.name] = {}
                }
                previous.originalMessage = validator.settings.messages[element.name].laravelValidationRemote
                validator.settings.messages[element.name].laravelValidationRemote = previous.message

                var param = (typeof param === 'string' && { url: param }) || param

                if (laravelValidation.helpers.arrayEquals(previous.old, value) || previous.old === value) {
                    return previous.valid
                }

                previous.old = value

                data = $(validator.currentForm).serializeArray()

                data.push({
                    name: '_js_validation',
                    value: attribute,
                })

                data.push({
                    name: '_js_validation_validate_all',
                    value: validateAll,
                })

                let formMethod = $(validator.currentForm).attr('method')

                validator.startRequest(element)

                $.ajax(
                    $.extend(
                        true,
                        {
                            mode: 'abort',
                            port: 'validate' + element.name,
                            dataType: 'json',
                            data: data,
                            context: validator.currentForm,
                            url: $(validator.currentForm).attr('action'),
                            type: formMethod,

                            beforeSend: function (xhr) {
                                if ($(validator.currentForm).attr('method').toLowerCase() !== 'get' && token) {
                                    return xhr.setRequestHeader('X-XSRF-TOKEN', token)
                                }
                            },
                            complete: function () {
                                $(validator.currentForm)
                                    .find('button[type=submit]')
                                    .prop('disabled', false)
                                    .removeClass('disabled')
                            },
                        },
                        param || {}
                    )
                ).always(function (response, textStatus) {
                    let errors, message, submitted, valid

                    if (textStatus === 'error') {
                        valid = false
                        response = laravelValidation.helpers.parseErrorResponse(response)
                    } else if (textStatus === 'success') {
                        valid = response === true || response === 'true'
                    } else {
                        return
                    }

                    validator.settings.messages[element.name].laravelValidationRemote = previous.originalMessage

                    if (valid) {
                        submitted = validator.formSubmitted
                        validator.prepareElement(element)
                        validator.formSubmitted = submitted
                        validator.successList.push(element)
                        delete validator.invalid[element.name]
                        validator.showErrors()
                    } else {
                        errors = {}
                        message = response || validator.defaultMessage(element, 'remote')
                        errors[element.name] = previous.message = $.isFunction(message) ? message(value) : message[0]
                        validator.invalid[element.name] = true
                        validator.showErrors(errors)
                    }
                    validator.showErrors(validator.errorMap)
                    previous.valid = valid
                    validator.stopRequest(element, valid)
                })

                return 'pending'
            },
            ''
        )
    },
}

