document.addEventListener('DOMContentLoaded', function () {
    const fixDatePickers = (form) => {
        const datePickers = form.querySelectorAll('.booking-date-picker');
        if (!datePickers.length) {
            return;
        }

        const formatDate = (date) => {
            if (!date) return '';
            // Handle cases where the value is already a string
            if (typeof date === 'string') {
                // Check if it's a valid date string before creating a new Date object
                if (!isNaN(Date.parse(date))) {
                    date = new Date(date);
                } else {
                    return date; // Return original string if it's not a valid date
                }
            }
            // Ensure it's a valid Date object
            if (Object.prototype.toString.call(date) !== '[object Date]' || isNaN(date)) {
                return '';
            }

            const year = date.getFullYear();
            const month = String(date.getMonth() + 1).padStart(2, '0');
            const day = String(date.getDate()).padStart(2, '0');
            return `${year}-${month}-${day}`;
        };

        datePickers.forEach(picker => {
            picker.addEventListener('change', (e) => {
                // Use a small timeout to allow the date picker plugin to set its value
                setTimeout(() => {
                    if (e.target.value) {
                        // Some pickers might return a Date object, some a string.
                        // We need to standardize it for the validator.
                        const rawValue = e.target.value;
                        const dateObject = new Date(rawValue);
                        e.target.value = formatDate(dateObject);
                    }
                }, 100);
            });
        });
    };

    // Apply the fix to all forms on the page that might have these fields
    document.querySelectorAll('form').forEach(form => {
        fixDatePickers(form);
    });

    // Also, handle dynamically loaded forms if any
    const observer = new MutationObserver((mutations) => {
        mutations.forEach((mutation) => {
            if (mutation.addedNodes.length) {
                mutation.addedNodes.forEach((node) => {
                    if (node.nodeType === 1 && node.tagName === 'FORM') {
                        fixDatePickers(node);
                    } else if (node.nodeType === 1) {
                        node.querySelectorAll('form').forEach(form => {
                            fixDatePickers(form);
                        });
                    }
                });
            }
        });
    });

    observer.observe(document.body, { childList: true, subtree: true });
});

